(window.webpackJsonp=window.webpackJsonp||[]).push([[26],{295:function(i,t,e){"use strict";e.r(t);var s=e(10),n=Object(s.a)({},(function(){var i=this,t=i._self._c;return t("ContentSlotsDistributor",{attrs:{"slot-key":i.$parent.slotKey}},[t("h1",{attrs:{id:"경제지표-economic-indicators"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#경제지표-economic-indicators"}},[i._v("#")]),i._v(" 경제지표 Economic-indicators")]),i._v(" "),t("div",{staticClass:"custom-block tip"},[t("p",{staticClass:"custom-block-title"},[i._v("경제지표 (Economic indicators)")]),i._v(" "),t("p",[i._v("경제 지표는 경제에 대한 통계이다. 경제의 성장과 발전으로 인하여 점점 다각적, 거시적인 분석과 논증을 필요로 하게 되었는데 이와 같은 모든 경제 현상이나 그 변화, 예측을 설명할 때 쓰이는 지표를 말한다."),t("br"),i._v("\n경제 지표들을 통해 경제적 성과와 미래 성과에 대한 예측을 분석할 수 있다. 경제 지표들의 한 응용으로는 경기 순환의 연구가 있다. 경제 지표에는 다양한 지수, 소득 보고, 경제 요약을 포함한다. 이를테면 실업률, 이직률, 주택 착공 건수, 소비자 물가지수 (인플레이션의 척도), 소비자 레버리지 비율, 산업 생산 지수, 파산, 국내 총생산, 광대역 인터넷 보급률, 소매 판매 지수, 주식 시장의 주가, 통화량의 변화 등을 들 수 있다.")])]),i._v(" "),t("div",{staticClass:"custom-block warning"},[t("p",{staticClass:"custom-block-title"},[i._v("Economic indicators")]),i._v(" "),t("p",[i._v("An economic indicator is a statistic about an economic activity. Economic indicators allow analysis of economic performance and predictions of future performance."),t("br"),i._v("\nOne application of economic indicators is the study of business cycles. Economic indicators include various indices, earnings reports, and economic summaries: for example, the unemployment rate, quits rate (quit rate in American English), housing starts, consumer price index (a measure for inflation), Inverted yield curve, consumer leverage ratio, industrial production, bankruptcies, gross domestic product, broadband internet penetration, retail sales, price index, and changes in credit conditions.")])]),i._v(" "),t("h2",{attrs:{id:"경기지표-business-indicators"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#경기지표-business-indicators"}},[i._v("#")]),i._v(" 경기지표 Business indicators")]),i._v(" "),t("div",{staticClass:"custom-block tip"},[t("p",{staticClass:"custom-block-title"},[i._v("경기지표 (Business indicators)")]),i._v(" "),t("p",[i._v("경기지표란 경기동향을 판단하기 위하여 이용하는 수량적인 지표를 말한다. 이것에는 기존의 통계적 계열 중에서 경기동향을 민감히 반영하는 것이라고 생각되는 계열을 그대로 이용하는 경우와 경기동향을 보기에 적합한 지표로 만드는 방법의 2가지가 있다."),t("br"),i._v("\n전자는 ① 생산활동, ② 상품의 수급상황, ③ 물가(기업수익·원가포함)의 동향, ④ 금융·통화의 움직임 등 경기동향을 집약한 4개의 국면에 관련된 통계지표를 말한다. 예를 들면 생산지수·출하지수·재고지수 등의 움직임, 또는 도매물가나 소비자물가의 동향이 주요한 판단재료이다."),t("br"),i._v("\n후자는 ① 바로미터(barometer)방정식, ② DI(diffusion index)방식, ③ 경기변동지표에 관한 센서스방식, ④ 비즈니스 서베이(business survey)방식, ⑤ 계량경제모델 방식 등으로 구별될 수 있다. 이 중에서 경기지표에 관련이 깊은 것은 ①∼③이다.")])]),i._v(" "),t("div",{staticClass:"custom-block warning"},[t("p",{staticClass:"custom-block-title"},[i._v("Business indicators")]),i._v(" "),t("p",[i._v("Economic indicators are quantitative indicators used to judge economic trends. Among the existing statistical systems, there are two ways to make economic trends an indicator suitable for viewing them."),t("br"),i._v("\nThe former refers to statistical indicators related to four phases that summarize economic trends, such as ① production activities, ② supply and demand status of goods, ③ trends in prices (including corporate income and costs), and ④ movements in finance and currency. For example, movements in production index, shipping index, inventory index, etc., or trends in wholesale or consumer prices are major judgment materials."),t("br"),i._v("\nThe latter can be divided into ① barometer equation, ② diffusion index (DI) method, ③ census method on economic fluctuation indicators, ④ business survey method, and ⑤ econometric model method. Among them, ① to ③ are deeply related to economic indicators.")])]),i._v(" "),t("h2",{attrs:{id:"시간에-따른-분류-classification-by-timing"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#시간에-따른-분류-classification-by-timing"}},[i._v("#")]),i._v(" 시간에 따른 분류 Classification by timing")]),i._v(" "),t("p",[i._v("경제 지표는 경기 순환(business cycle)에 관한 시간에 따라 선행 지표(leading indicator), 후행 지표(lagging indicator), 동행 지표(coincident indicator)로 나뉜다.")]),i._v(" "),t("p",[i._v("Economic indicators can be classified into three categories according to their usual timing in relation to the business cycle: leading indicators, lagging indicators, and coincident indicators.")]),i._v(" "),t("h3",{attrs:{id:"선행-지표-leading-indicators"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#선행-지표-leading-indicators"}},[i._v("#")]),i._v(" 선행 지표 Leading indicators")]),i._v(" "),t("div",{staticClass:"custom-block tip"},[t("p",{staticClass:"custom-block-title"},[i._v("선행지표 (Leading indicators)")]),i._v(" "),t("p",[i._v("선행 지표는 경기가 전체적으로 바뀌기 전에 바뀌는 지표이다. 따라서 선행 지표는 유용한 경기 단기 예측 변수(short-term predicator)이다. 주식수익률(tock market return)은 선행지표이다. 주식시장은 경기가 전체적으로 하강하기 전에 먼저 하강하고. 경기가 침체에서 벗어나기 전에 먼저 상승한다.\n다른 선행 지표는 소비자 기대지수(index of consumer expectations), 건설 허가(building permits), 통화공급량(money supply)이다."),t("br"),i._v("\n미국 컨퍼런스 보드(The Conference Board)는 향후 6-9개월 미국 경제 활동을 예측하도록 설계된 10개의 지표로 구성된 종합 컨퍼런스 보드 선행 경기 지수(Conference Board Leading Economic Index)를 발표한다.")])]),i._v(" "),t("div",{staticClass:"custom-block warning"},[t("p",{staticClass:"custom-block-title"},[i._v("Leading indicators")]),i._v(" "),t("p",[i._v("Leading indicators are indicators that usually, but not always, change before the economy as a whole changes. They are therefore useful as short-term predictors of the economy."),t("br"),i._v("\nLeading indicators include the index of consumer expectations, building permits, and credit conditions."),t("br"),i._v("\nThe Conference Board publishes a composite Leading Economic Index consisting of ten indicators designed to predict activity in the U. S. economy six to nine months in future.")])]),i._v(" "),t("h3",{attrs:{id:"후행-지표-lagging-indicators"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#후행-지표-lagging-indicators"}},[i._v("#")]),i._v(" 후행 지표 Lagging indicators")]),i._v(" "),t("div",{staticClass:"custom-block tip"},[t("p",{staticClass:"custom-block-title"},[i._v("후행 지표 (Lagging indicators)")]),i._v(" "),t("p",[i._v("후행 지표는 경기가 전체적으로 바뀐 후에 바뀌는 지표이다. 보통 경기후퇴(lag)는 1년의 몇 분기에 해당한다. 실업률(unemployment rate)은 후행 지표이다. 고용(employment)은 일반경제의 경기호전(upturn) 이후 2-3분기 늘어나는 경향이 있다. 금융에서 볼린저 밴드(Bollinger band)는 자주 사용되는 후행 지표 중 하나이다. 실적 측정 시스템(performance measuring system)에서, 한 사업을 통해 벌어들인 수익은 과거 실적(historical performance)을 반영한다는 점에서 후행지표에 해당한다. 이와 유사하게, 소비자 만족도 상승은 이전의 발의 사항이 반영된 결과이다.")])]),i._v(" "),t("div",{staticClass:"custom-block warning"},[t("p",{staticClass:"custom-block-title"},[i._v("Lagging indicators")]),i._v(" "),t("p",[i._v("Lagging indicators are indicators that usually change after the economy as a whole does. Typically the lag is a few quarters of a year. The unemployment rate is a lagging indicator: employment tends to increase two or three quarters after an upturn in the general economy. In a performance measuring system, profit earned by a business is a lagging indicator as it reflects a historical performance; similarly, improved customer satisfaction is the result of initiatives taken in the past.")])]),i._v(" "),t("h3",{attrs:{id:"동행-지표-coincident-indicators"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#동행-지표-coincident-indicators"}},[i._v("#")]),i._v(" 동행 지표 Coincident indicators")]),i._v(" "),t("div",{staticClass:"custom-block tip"},[t("p",{staticClass:"custom-block-title"},[i._v("동행 지표 (Coincident indicators)")]),i._v(" "),t("p",[i._v("동행 지표는 경기 전체와 거의 동시에 바뀌며, 따라서 경기의 최신 상황 관련 정보를 제공한다. GDP(Gross Domestic Product), 기업 생산률(industrial production), 개인 소득(personal income), 소매상 판매고(retail sales) 등이 경기 동행 지표에 해당한다. 동행지수는 어느 정도 시간 경과 이후, 경기 순환의 최고점과 최저점(peaks and troughs) 날짜를 확인하는데 사용된다.")])]),i._v(" "),t("div",{staticClass:"custom-block warning"},[t("p",{staticClass:"custom-block-title"},[i._v("Coincident indicators")]),i._v(" "),t("p",[i._v("Coincident indicators change at approximately the same time as the whole economy, thereby providing information about the current state of the economy. There are many coincident economic indicators, such as Gross Domestic Product, industrial production, personal income and retail sales. A coincident index may be used to identify, after the fact, the dates of peaks and troughs in the business cycle.")])])])}),[],!1,null,null,null);t.default=n.exports}}]);